import{c as t,cG as d,cb as r,c8 as e,cf as s,cT as o,ce as a}from"./chunks/framework.BlkIsu1j.js";const c=JSON.parse('{"title":"附录 A. RV64I 基础指令速查表","description":"","frontmatter":{"title":"附录 A. RV64I 基础指令速查表","outline":"deep","layout":"doc","prev":{"text":"22. 页表与虚拟内存","link":"/lang/assembly/22_virtual_memory"},"next":{"text":"附录 B. 标准扩展指令速查表","link":"/lang/assembly/appendix_b_extensions_reference"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/appendix_a_rv64i_reference.md","filePath":"lang/assembly/appendix_a_rv64i_reference.md","lastUpdated":1780203693000}'),i={id:"frontmatter-title",tabindex:"-1"};const l=t({name:"lang/assembly/appendix_a_rv64i_reference.md"},[["render",function(t,c,l,h,m,n){return d(),r("div",null,[e("h1",i,[s(o(t.$frontmatter.title)+" ",1),c[0]||(c[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),c[1]||(c[1]=a('<p>RV64I 是 RISC-V 64 位基础整数指令集，共 50 条基础指令（不含扩展）。所有指令按功能分组，按指令格式（R/I/S/B/U/J）组织编码。本节是完整速查表，供编程时快速查阅指令的操作语义、funct3 和 funct7 编码。</p><h2 id="算术运算-r-type-opcode-0110011" tabindex="-1">算术运算（R-type，opcode=0110011） <a class="header-anchor" href="#算术运算-r-type-opcode-0110011" aria-label="Permalink to “算术运算（R-type，opcode=0110011）”">​</a></h2><p>寄存器-寄存器操作。rs1、rs2 为源寄存器，rd 为目的寄存器。</p><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct3</th><th>funct7</th></tr></thead><tbody><tr><td><code>add rd, rs1, rs2</code></td><td>rd = rs1 + rs2</td><td>000</td><td>0000000</td></tr><tr><td><code>sub rd, rs1, rs2</code></td><td>rd = rs1 - rs2</td><td>000</td><td>0100000</td></tr><tr><td><code>sll rd, rs1, rs2</code></td><td>rd = rs1 &lt;&lt; rs2[5:0]</td><td>001</td><td>0000000</td></tr><tr><td><code>slt rd, rs1, rs2</code></td><td>rd = (rs1 &lt; rs2) ? 1 : 0（有符号）</td><td>010</td><td>0000000</td></tr><tr><td><code>sltu rd, rs1, rs2</code></td><td>rd = (rs1 &lt; rs2) ? 1 : 0（无符号）</td><td>011</td><td>0000000</td></tr><tr><td><code>xor rd, rs1, rs2</code></td><td>rd = rs1 ^ rs2</td><td>100</td><td>0000000</td></tr><tr><td><code>srl rd, rs1, rs2</code></td><td>rd = rs1 &gt;&gt; rs2[5:0]（逻辑右移）</td><td>101</td><td>0000000</td></tr><tr><td><code>sra rd, rs1, rs2</code></td><td>rd = rs1 &gt;&gt; rs2[5:0]（算术右移）</td><td>101</td><td>0100000</td></tr><tr><td><code>or rd, rs1, rs2</code></td><td>rd = rs1 | rs2</td><td>110</td><td>0000000</td></tr><tr><td><code>and rd, rs1, rs2</code></td><td>rd = rs1 &amp; rs2</td><td>111</td><td>0000000</td></tr></tbody></table><blockquote><p><strong>注意</strong>：RV64I 中所有 R-type 算术指令默认为 64 位操作。RV32I 中同样指令操作 32 位数据。</p></blockquote><h2 id="立即数算术运算-i-type-opcode-0010011" tabindex="-1">立即数算术运算（I-type，opcode=0010011） <a class="header-anchor" href="#立即数算术运算-i-type-opcode-0010011" aria-label="Permalink to “立即数算术运算（I-type，opcode=0010011）”">​</a></h2><p>寄存器与 12 位有符号立即数操作。</p><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct3</th></tr></thead><tbody><tr><td><code>addi rd, rs1, imm</code></td><td>rd = rs1 + imm（符号扩展）</td><td>000</td></tr><tr><td><code>slli rd, rs1, shamt</code></td><td>rd = rs1 &lt;&lt; shamt（shamt[5:0]，高位移出）</td><td>001</td></tr><tr><td><code>slti rd, rs1, imm</code></td><td>rd = (rs1 &lt; imm) ? 1 : 0（有符号）</td><td>010</td></tr><tr><td><code>sltiu rd, rs1, imm</code></td><td>rd = (rs1 &lt; imm) ? 1 : 0（无符号）</td><td>011</td></tr><tr><td><code>xori rd, rs1, imm</code></td><td>rd = rs1 ^ imm</td><td>100</td></tr><tr><td><code>srli rd, rs1, shamt</code></td><td>rd = rs1 &gt;&gt; shamt（逻辑，shamt[5:0]）</td><td>101</td></tr><tr><td><code>srai rd, rs1, shamt</code></td><td>rd = rs1 &gt;&gt; shamt（算术，shamt[5:0]）</td><td>101</td></tr><tr><td><code>ori rd, rs1, imm</code></td><td>rd = rs1 | imm</td><td>110</td></tr><tr><td><code>andi rd, rs1, imm</code></td><td>rd = rs1 &amp; imm</td><td>111</td></tr></tbody></table><blockquote><p><strong>移位立即数</strong>：slli/srli/srai 的 shamt 取低 6 位（0-63），funct7 用于区分 srli（0000000）和 srai（0100000），汇编器根据指令名自动填入。</p></blockquote><h2 id="rv64i-特有-32-位算术运算-r-type-opcode-0111011" tabindex="-1">RV64I 特有 32 位算术运算（R-type，opcode=0111011） <a class="header-anchor" href="#rv64i-特有-32-位算术运算-r-type-opcode-0111011" aria-label="Permalink to “RV64I 特有 32 位算术运算（R-type，opcode=0111011）”">​</a></h2><p>操作 32 位数据，结果符号扩展至 64 位写入 rd。</p><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct3</th><th>funct7</th></tr></thead><tbody><tr><td><code>addw rd, rs1, rs2</code></td><td>rd = sign_extend((rs1 + rs2)[31:0])</td><td>000</td><td>0000000</td></tr><tr><td><code>subw rd, rs1, rs2</code></td><td>rd = sign_extend((rs1 - rs2)[31:0])</td><td>000</td><td>0100000</td></tr><tr><td><code>sllw rd, rs1, rs2</code></td><td>rd = sign_extend(rs1[31:0] &lt;&lt; rs2[4:0])</td><td>001</td><td>0000000</td></tr><tr><td><code>srlw rd, rs1, rs2</code></td><td>rd = sign_extend(rs1[31:0] &gt;&gt; rs2[4:0] 逻辑)</td><td>101</td><td>0000000</td></tr><tr><td><code>sraw rd, rs1, rs2</code></td><td>rd = sign_extend(rs1[31:0] &gt;&gt; rs2[4:0] 算术)</td><td>101</td><td>0100000</td></tr></tbody></table><h2 id="rv64i-特有-32-位立即数运算-i-type-opcode-0011011" tabindex="-1">RV64I 特有 32 位立即数运算（I-type，opcode=0011011） <a class="header-anchor" href="#rv64i-特有-32-位立即数运算-i-type-opcode-0011011" aria-label="Permalink to “RV64I 特有 32 位立即数运算（I-type，opcode=0011011）”">​</a></h2><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct3</th></tr></thead><tbody><tr><td><code>addiw rd, rs1, imm</code></td><td>rd = sign_extend((rs1 + imm)[31:0])</td><td>000</td></tr><tr><td><code>slliw rd, rs1, shamt</code></td><td>rd = sign_extend(rs1[31:0] &lt;&lt; shamt[4:0])</td><td>001</td></tr><tr><td><code>srliw rd, rs1, shamt</code></td><td>rd = sign_extend(rs1[31:0] &gt;&gt; shamt[4:0] 逻辑)</td><td>101</td></tr><tr><td><code>sraiw rd, rs1, shamt</code></td><td>rd = sign_extend(rs1[31:0] &gt;&gt; shamt[4:0] 算术)</td><td>101</td></tr></tbody></table><blockquote><p><strong>注意</strong>：W 后缀指令的移位量仅取低 5 位（0-31）。slliw/srliw/sraiw 的 funct7 用于区分 srliw（0000000）和 sraiw（0100000）。</p></blockquote><h2 id="load-指令-i-type-opcode-0000011" tabindex="-1">Load 指令（I-type，opcode=0000011） <a class="header-anchor" href="#load-指令-i-type-opcode-0000011" aria-label="Permalink to “Load 指令（I-type，opcode=0000011）”">​</a></h2><p>从内存加载数据到寄存器。地址 = rs1 + imm（12 位有符号立即数）。</p><table tabindex="0"><thead><tr><th>指令</th><th>位宽</th><th>符号扩展</th><th>操作语义</th><th>funct3</th></tr></thead><tbody><tr><td><code>lb rd, imm(rs1)</code></td><td>8</td><td>是</td><td>rd = sign_extend(M[rs1+imm][7:0])</td><td>000</td></tr><tr><td><code>lh rd, imm(rs1)</code></td><td>16</td><td>是</td><td>rd = sign_extend(M[rs1+imm][15:0])</td><td>001</td></tr><tr><td><code>lw rd, imm(rs1)</code></td><td>32</td><td>是</td><td>rd = sign_extend(M[rs1+imm][31:0])</td><td>010</td></tr><tr><td><code>ld rd, imm(rs1)</code></td><td>64</td><td>—</td><td>rd = M[rs1+imm][63:0]</td><td>011</td></tr><tr><td><code>lbu rd, imm(rs1)</code></td><td>8</td><td>零扩展</td><td>rd = zero_extend(M[rs1+imm][7:0])</td><td>100</td></tr><tr><td><code>lhu rd, imm(rs1)</code></td><td>16</td><td>零扩展</td><td>rd = zero_extend(M[rs1+imm][15:0])</td><td>101</td></tr><tr><td><code>lwu rd, imm(rs1)</code></td><td>32</td><td>零扩展</td><td>rd = zero_extend(M[rs1+imm][31:0])</td><td>110</td></tr></tbody></table><h2 id="store-指令-s-type-opcode-0100011" tabindex="-1">Store 指令（S-type，opcode=0100011） <a class="header-anchor" href="#store-指令-s-type-opcode-0100011" aria-label="Permalink to “Store 指令（S-type，opcode=0100011）”">​</a></h2><p>将寄存器数据写入内存。地址 = rs1 + imm（12 位有符号立即数，inst[31:25] 存放 imm[11:5]，inst[11:7] 存放 imm[4:0]）。</p><table tabindex="0"><thead><tr><th>指令</th><th>位宽</th><th>操作语义</th><th>funct3</th></tr></thead><tbody><tr><td><code>sb rs2, imm(rs1)</code></td><td>8</td><td>M[rs1+imm][7:0] = rs2[7:0]</td><td>000</td></tr><tr><td><code>sh rs2, imm(rs1)</code></td><td>16</td><td>M[rs1+imm][15:0] = rs2[15:0]</td><td>001</td></tr><tr><td><code>sw rs2, imm(rs1)</code></td><td>32</td><td>M[rs1+imm][31:0] = rs2[31:0]</td><td>010</td></tr><tr><td><code>sd rs2, imm(rs1)</code></td><td>64</td><td>M[rs1+imm][63:0] = rs2[63:0]</td><td>011</td></tr></tbody></table><h2 id="分支指令-b-type-opcode-1100011" tabindex="-1">分支指令（B-type，opcode=1100011） <a class="header-anchor" href="#分支指令-b-type-opcode-1100011" aria-label="Permalink to “分支指令（B-type，opcode=1100011）”">​</a></h2><p>比较 rs1 与 rs2，条件满足时跳转至 PC + imm（imm 为 13 位有符号立即数，以 2 字节为单位的偏移量）。B-type 编码：inst[31]=imm[12]，inst[7]=imm[11]，inst[30:25]=imm[10:5]，inst[11:8]=imm[4:1]。</p><table tabindex="0"><thead><tr><th>指令</th><th>条件</th><th>说明</th><th>funct3</th></tr></thead><tbody><tr><td><code>beq rs1, rs2, label</code></td><td>rs1 == rs2</td><td>相等则跳转</td><td>000</td></tr><tr><td><code>bne rs1, rs2, label</code></td><td>rs1 != rs2</td><td>不等则跳转</td><td>001</td></tr><tr><td><code>blt rs1, rs2, label</code></td><td>rs1 &lt; rs2</td><td>有符号小于</td><td>100</td></tr><tr><td><code>bge rs1, rs2, label</code></td><td>rs1 &gt;= rs2</td><td>有符号大于等于</td><td>101</td></tr><tr><td><code>bltu rs1, rs2, label</code></td><td>rs1 &lt; rs2</td><td>无符号小于</td><td>110</td></tr><tr><td><code>bgeu rs1, rs2, label</code></td><td>rs1 &gt;= rs2</td><td>无符号大于等于</td><td>111</td></tr></tbody></table><h2 id="跳转指令" tabindex="-1">跳转指令 <a class="header-anchor" href="#跳转指令" aria-label="Permalink to “跳转指令”">​</a></h2><table tabindex="0"><thead><tr><th>指令</th><th>格式</th><th>操作语义</th></tr></thead><tbody><tr><td><code>jal rd, label</code></td><td>J-type</td><td>rd = PC+4; PC = PC + offset（21 位有符号立即数，2 字节对齐）</td></tr><tr><td><code>jalr rd, imm(rs1)</code></td><td>I-type</td><td>rd = PC+4; PC = (rs1 + imm) &amp; ~1</td></tr></tbody></table><blockquote><p><strong>J-type 立即数编码</strong>：inst[31]=imm[20]，inst[19:12]=imm[19:12]，inst[20]=imm[11]，inst[30:21]=imm[10:1]。最终跳转偏移 = {imm[20], imm[1], imm[11], imm[19:12], imm[10:5], imm[4:1], 1&#39;b0}。</p></blockquote><h2 id="load-upper-add-upper-指令-u-type" tabindex="-1">Load Upper / Add Upper 指令（U-type） <a class="header-anchor" href="#load-upper-add-upper-指令-u-type" aria-label="Permalink to “Load Upper / Add Upper 指令（U-type）”">​</a></h2><p>U-type 格式：20 位立即数存放于指令的 [31:12] 位，写入 rd 的高 20 位。</p><table tabindex="0"><thead><tr><th>指令</th><th>格式</th><th>操作语义</th><th>opcode</th></tr></thead><tbody><tr><td><code>lui rd, imm</code></td><td>U-type</td><td>rd = imm &lt;&lt; 12（低 12 位填 0）</td><td>0110111</td></tr><tr><td><code>auipc rd, imm</code></td><td>U-type</td><td>rd = PC + (imm &lt;&lt; 12)</td><td>0010111</td></tr></tbody></table><h2 id="系统指令-i-type-opcode-1110011" tabindex="-1">系统指令（I-type，opcode=1110011） <a class="header-anchor" href="#系统指令-i-type-opcode-1110011" aria-label="Permalink to “系统指令（I-type，opcode=1110011）”">​</a></h2><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct3</th><th>说明</th></tr></thead><tbody><tr><td><code>ecall</code></td><td>触发环境调用异常</td><td>000</td><td>系统调用 / 调试</td></tr><tr><td><code>ebreak</code></td><td>触发断点异常</td><td>000</td><td>调试器断点</td></tr><tr><td><code>fence iorw, iorw</code></td><td>内存访问顺序约束</td><td>001</td><td>多核/IO 同步</td></tr><tr><td><code>fence.i</code></td><td>指令缓存同步</td><td>001</td><td>自修改代码后使用</td></tr></tbody></table><blockquote><p>ecall 和 ebreak 的 funct12 字段不同：ecall=000000000000，ebreak=000000000001。</p></blockquote><h2 id="控制状态寄存器-csr-指令-i-type-opcode-1110011" tabindex="-1">控制状态寄存器（CSR）指令（I-type，opcode=1110011） <a class="header-anchor" href="#控制状态寄存器-csr-指令-i-type-opcode-1110011" aria-label="Permalink to “控制状态寄存器（CSR）指令（I-type，opcode=1110011）”">​</a></h2><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct3</th></tr></thead><tbody><tr><td><code>csrrw rd, csr, rs1</code></td><td>rd = CSR; CSR = rs1（原子读写）</td><td>001</td></tr><tr><td><code>csrrs rd, csr, rs1</code></td><td>rd = CSR; CSR = CSR | rs1（原子读后置位）</td><td>010</td></tr><tr><td><code>csrrc rd, csr, rs1</code></td><td>rd = CSR; CSR = CSR &amp; ~rs1（原子读后清除）</td><td>011</td></tr><tr><td><code>csrrwi rd, csr, uimm</code></td><td>rd = CSR; CSR = uimm（立即数原子读写）</td><td>101</td></tr><tr><td><code>csrrsi rd, csr, uimm</code></td><td>rd = CSR; CSR = CSR | uimm（立即数读后置位）</td><td>110</td></tr><tr><td><code>csrrci rd, csr, uimm</code></td><td>rd = CSR; CSR = CSR &amp; ~uimm（立即数读后清除）</td><td>111</td></tr></tbody></table><blockquote><p>rs1/uimm 为 x0 时，CSR 不写入（伪读操作）。rd 为 x0 时，CSR 旧值丢弃（伪写操作）。</p></blockquote><h2 id="opcode-速查表" tabindex="-1">opcode 速查表 <a class="header-anchor" href="#opcode-速查表" aria-label="Permalink to “opcode 速查表”">​</a></h2><table tabindex="0"><thead><tr><th>opcode[6:0]</th><th>指令类型</th><th>格式</th></tr></thead><tbody><tr><td>0110111</td><td><code>lui</code></td><td>U-type</td></tr><tr><td>0010111</td><td><code>auipc</code></td><td>U-type</td></tr><tr><td>1101111</td><td><code>jal</code></td><td>J-type</td></tr><tr><td>1100111</td><td><code>jalr</code></td><td>I-type</td></tr><tr><td>1100011</td><td>分支指令（beq/bne/blt/bge/bltu/bgeu）</td><td>B-type</td></tr><tr><td>0000011</td><td>Load 指令（lb/lh/lw/ld/lbu/lhu/lwu）</td><td>I-type</td></tr><tr><td>0100011</td><td>Store 指令（sb/sh/sw/sd）</td><td>S-type</td></tr><tr><td>0010011</td><td>立即数算术（addi/slti/sltiu/xori/ori/andi/slli/srli/srai）</td><td>I-type</td></tr><tr><td>0110011</td><td>寄存器算术（add/sub/sll/slt/sltu/xor/srl/sra/or/and）</td><td>R-type</td></tr><tr><td>0011011</td><td>RV64I 32 位立即数算术（addiw/slliw/srliw/sraiw）</td><td>I-type</td></tr><tr><td>0111011</td><td>RV64I 32 位寄存器算术（addw/subw/sllw/srlw/sraw）</td><td>R-type</td></tr><tr><td>0001111</td><td>FENCE / FENCE.I</td><td>I-type</td></tr><tr><td>1110011</td><td>系统指令（ecall/ebreak/CSR）</td><td>I-type</td></tr></tbody></table><h2 id="指令格式位域速查" tabindex="-1">指令格式位域速查 <a class="header-anchor" href="#指令格式位域速查" aria-label="Permalink to “指令格式位域速查”">​</a></h2><table tabindex="0"><thead><tr><th>格式</th><th>位域布局</th></tr></thead><tbody><tr><td><strong>R-type</strong></td><td>funct7[31:25] | rs2[24:20] | rs1[19:15] | funct3[14:12] | rd[11:7] | opcode[6:0]</td></tr><tr><td><strong>I-type</strong></td><td>imm[11:0][31:20] | rs1[19:15] | funct3[14:12] | rd[11:7] | opcode[6:0]</td></tr><tr><td><strong>S-type</strong></td><td>imm[11:5][31:25] | rs2[24:20] | rs1[19:15] | funct3[14:12] | imm[4:0][11:7] | opcode[6:0]</td></tr><tr><td><strong>B-type</strong></td><td>imm[12|10:5][31:25] | rs2[24:20] | rs1[19:15] | funct3[14:12] | imm[4:1|11][11:7] | opcode[6:0]</td></tr><tr><td><strong>U-type</strong></td><td>imm[31:12][31:12] | rd[11:7] | opcode[6:0]</td></tr><tr><td><strong>J-type</strong></td><td>imm[20|10:1|11|19:12][31:12] | rd[11:7] | opcode[6:0]</td></tr></tbody></table><h2 id="指令数统计" tabindex="-1">指令数统计 <a class="header-anchor" href="#指令数统计" aria-label="Permalink to “指令数统计”">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>指令数</th><th>备注</th></tr></thead><tbody><tr><td>寄存器算术</td><td>10</td><td>add/sub/sll/slt/sltu/xor/srl/sra/or/and</td></tr><tr><td>立即数算术</td><td>9</td><td>addi/slli/slti/sltiu/xori/srli/srai/ori/andi</td></tr><tr><td>RV64 W 寄存器算术</td><td>5</td><td>addw/subw/sllw/srlw/sraw</td></tr><tr><td>RV64 W 立即数算术</td><td>4</td><td>addiw/slliw/srliw/sraiw</td></tr><tr><td>Load</td><td>7</td><td>lb/lh/lw/ld/lbu/lhu/lwu</td></tr><tr><td>Store</td><td>4</td><td>sb/sh/sw/sd</td></tr><tr><td>分支</td><td>6</td><td>beq/bne/blt/bge/bltu/bgeu</td></tr><tr><td>跳转</td><td>2</td><td>jal/jalr</td></tr><tr><td>Upper</td><td>2</td><td>lui/auipc</td></tr><tr><td>系统</td><td>4</td><td>ecall/ebreak/fence/fence.i</td></tr><tr><td>CSR</td><td>6</td><td>csrrw/csrrs/csrrc/csrrwi/csrrsi/csrrci</td></tr><tr><td><strong>合计</strong></td><td><strong>59</strong></td><td></td></tr></tbody></table>',42))])}]]);export{c as __pageData,l as default};
